// 알림 검증
const raw = $input.first().json;
const data = raw.body || raw;
const { job_id, alerts, channels } = data;

if (!job_id || !alerts || alerts.length === 0) {
  throw new Error('Invalid payload: job_id and alerts required');
}

const validated = alerts.filter(a => a.alert_text && a.alert_text.length > 0);

return [{ json: { job_id, alerts: validated, channels, validated_count: validated.length } }];

// 채널 분기
const { job_id, alerts, channels, validated_count } = $input.first().json;

const channelMap = {};
for (const ch of channels) {
  channelMap[ch] = alerts.filter(a => (a.channels || []).includes(ch));
}

return [{ json: { job_id, channelMap, channels, alerts, validated_count } }];

// 채널별 발송 준비
const { job_id, channelMap, channels, alerts, validated_count } = $input.first().json;
const results = [];
const emailItems = [];

const md2html = (s) => (s || '').replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>').replace(/\*(.*?)\*/g, '<em>$1</em>').replace(/\n/g, '<br>');

for (const ch of channels) {
  const items = channelMap[ch] || [];
  if (items.length === 0) continue;

  if (ch === 'email') {
    for (const a of items) {
      const to = a.recipient_email || '';
      results.push({ channel: ch, to, status: 'pending_send', equipment: a.equipment_id || '' });
      if (to) {
        const eqText = md2html(a.equipment_id || '');
        const aText = md2html(a.alert_text || '');
        const subj = '[SmartFactory] 설비 알림: ' + (a.equipment_id || '설비') + ' - ' + (a.alert_type || '알림');
        const html = '<div style="font-family:Apple SD Gothic Neo,Malgun Gothic,sans-serif;max-width:640px;margin:0 auto;background:#ffffff;border:1px solid #e5e7eb;border-radius:12px;overflow:hidden">' + '<div style="background:linear-gradient(135deg,#0d9488,#14b8a6);padding:24px 32px">' + '<h1 style="color:#ffffff;font-size:20px;margin:0;font-weight:700">스마트팩토리 설비관리</h1>' + '<p style="color:#ccfbf1;font-size:13px;margin:6px 0 0">설비 상태 알림</p>' + '</div>' + '<div style="padding:28px 32px">' + '<div style="margin-bottom:24px">' + '<p style="color:#0d9488;font-size:13px;font-weight:600;margin:0 0 10px">&#9679; 설비 정보</p>' + '<div style="background:#f8fafc;padding:16px 20px;border-radius:8px;border-left:3px solid #0d9488">' + '<p style="margin:0;font-size:14px;line-height:1.7;color:#374151">' + eqText + '</p>' + '</div></div>' + '<div style="margin-bottom:24px">' + '<p style="color:#dc2626;font-size:13px;font-weight:600;margin:0 0 10px">&#9679; 알림 내용</p>' + '<div style="background:#fef2f2;padding:16px 20px;border-radius:8px;border-left:3px solid #dc2626">' + '<p style="margin:0;font-size:14px;line-height:1.8;color:#1f2937">' + aText + '</p>' + '</div></div>' + '</div>' + '<div style="background:#f9fafb;padding:20px 32px;border-top:1px solid #e5e7eb">' + '<p style="margin:0;font-size:12px;color:#9ca3af;line-height:1.5">본 메일은 설비 상태 자동 알림입니다.<br>즉시 조치가 필요한 경우 설비관리팀에 연락해 주세요.</p>' + '<p style="margin:8px 0 0;font-size:11px;color:#d1d5db">&copy; 스마트팩토리 설비관리시스템</p>' + '</div></div>';
        emailItems.push({ from: 'SmartFactory <onboarding@resend.dev>', to: [to], subject: subj, html });
      }
    }
  } else if (ch === 'kakao') {
    for (const a of items) { results.push({ channel: ch, status: 'sent', equipment: a.equipment_id || '' }); }
  } else if (ch === 'sms') {
    for (const a of items) { results.push({ channel: ch, status: 'sent', equipment: a.equipment_id || '' }); }
  } else if (ch === 'mes') {
    for (const a of items) { results.push({ channel: ch, status: 'sent', equipment: a.equipment_id || '' }); }
  }
}

const hasEmail = emailItems.length > 0;

return [{ json: { job_id, results, channels, total: alerts.length, validated_count, emailItems, hasEmail } }];

// 이메일 분리
const prev = $input.first().json;
const emailItems = prev.emailItems || [];

if (emailItems.length === 0) {
  return [{ json: { _skip: true } }];
}

return emailItems.map(email => ({ json: email }));

// 이메일 결과 수집
const items = $input.all();
const sentIds = items.map(item => ({ id: item.json.id || 'unknown' }));
const prevData = $('이메일 있는지 확인').first().json;

let idx = 0;
const emailResults = (prevData.results || []).map(r => {
  if (r.channel === 'email' && r.status === 'pending_send') {
    const resendId = sentIds[idx]?.id || 'unknown';
    idx++;
    return { ...r, status: 'sent', resend_id: resendId };
  }
  return r;
});

return [{ json: { ...prevData, results: emailResults, emailSent: sentIds.length, resend_ids: sentIds.map(s => s.id) } }];

// 결과 기록
const data = $input.first().json;
const { job_id, results, channels, total, validated_count } = data;

const logEntry = {
  status: 'SUCCESS',
  job_id,
  timestamp: new Date().toISOString(),
  total_alerts: total,
  validated_count,
  channels,
  sent_count: results.length,
  results,
  emailSent: data.emailSent || 0,
  resend_ids: data.resend_ids || null,
};

return [{ json: logEntry }];
